const unit_tests_md = "# Unit Tests\n\n## Purpose\n\nDefine how AI should write and maintain unit tests in this repo.\n\n## Do\n\n- **Cover edge cases** – null, undefined, empty, boundary values\n- **Test error paths** – not just happy paths\n- **Keep tests fast** – mock external dependencies (APIs, databases)\n- **Test one thing per test** – one assertion, one reason to fail\n\n## Don't\n\n- **Don't test implementation details** – test behavior, not private methods\n- **Don't write flaky tests** – avoid timeouts, race conditions\n- **Don't mock everything** – test real logic when possible\n\n## Test structure\n\nUse Given / When / Then:\n\n```javascript\nit(\"returns error given duplicate email\", async () => {\n  // Given\n  await createUser({ email: \"test@example.com\" });\n\n  // When\n  const result = createUser({ email: \"test@example.com\" });\n\n  // Then\n  await expect(result).rejects.toThrow(\"Email already exists\");\n});\n```\n";

const naming_md = "# Naming Conventions\n\n## Purpose\n\nDefine naming standards for consistency across the codebase.\n\n## Do\n\n- **Be consistent with existing patterns** – if the repo uses `fetch*`, don't introduce `get*`\n- **Match domain language** – use terms from the product and business, not generic tech terms\n- **Use clear boolean names** – `isActive`, `hasPermission`, `canEdit`\n\n## Don't\n\n- **Don't use misleading names** – `get*` should not modify state; `create*` should not read\n- **Don't use generic names** – `handler`, `manager`, `helper`, `utils` without context\n";

const maintainability_md = "# Maintainability\n\n## Purpose\n\nDefine standards that keep the codebase readable, consistent, and easy to change.\n\n## Do\n\n- **Keep functions small** – one function, one job; split when it needs a comment to explain what it does\n- **One level of abstraction per function** – a function should either orchestrate other functions OR handle low-level detail, never both; the moment it mixes levels, extract the low-level part into a named helper\n- **Keep files focused** – one responsibility per file\n- **Use guard clauses** – return early to avoid deep nesting\n- **Name constants** – no magic numbers or strings inline\n- **Delete dead code** – unused code belongs in Git history, not the codebase\n- **Limit function parameters** – prefer an options object for 3+ params\n- **Enforce formatting with tooling** – linter/formatter decisions are not for code review\n\n## Don't\n\n- **Don't repeat logic** – if you write it twice, extract it\n";

const refactoring_md = "# Refactoring\n\n## Purpose\n\nDefine how to safely clean up a codebase without breaking behavior or overloading context.\n\n## Do\n\n- **Work one file at a time** – complete, confirm, then move to the next; never refactor across multiple files in one pass\n- **Apply the boy scout rule** – leave code you touch cleaner than you found it; ignore code you don't touch\n- **Separate refactoring from behavior changes** – never mix a rename, extract, or restructure with a feature or fix; keep them in separate commits\n- **Check all callsites before renaming** – if a name is used in more than one place, verify every reference before changing it\n- **Extract incrementally** – one concept per extraction; don't chain multiple refactors in a single step\n- **Flatten abstraction levels in functions** – if a function mixes high-level orchestration with low-level implementation detail, extract the detail into a named helper; the function should read like a table of contents, not an implementation\n- **Split classes and components with multiple responsibilities** – if a class or component has more than one reason to change, split it one responsibility at a time; this is the highest-risk refactor and must never be done in a single pass\n\n## Don't\n\n- **Don't rewrite** – refactoring is restructuring, not rewriting; if the logic is wrong, fix it separately\n\n## Note\n\nWhen asked to refactor a file: read it, identify the single highest-value change, apply it, stop. Ask before continuing to the next file or the next change.\n";

const logging_md = "# Logging\n\n## Purpose\n\nDefine what, when, and how to log so production signals remain useful and clean.\n\n## Do\n\n- **Use structured logging** – emit JSON with consistent fields: `level`, `message`, `timestamp`, and relevant context\n- **Log at boundaries** – service entry/exit, external calls, job start/completion; not inside every function\n- **Include enough context to diagnose** – request ID, resource ID, operation name; enough to reproduce without loading the full file\n\n## Don't\n\n- **Don't log inside loops** – aggregate and log once after the loop\n- **Don't use console.log in production code** – use a structured logger\n";

const architecture_md = "# Architecture\n\n## Purpose\n\nDefine architectural patterns and organization principles for this repo.\n\n## Do\n\n- **Follow existing patterns** – if the repo has a structure, maintain it\n- **Put code in the right place** – controllers, services, models, utils\n- **Reuse existing utilities** – check before creating new helper functions\n- **Separate concerns** – business logic, data access, presentation in distinct layers\n- **One responsibility per class or component** – a class or component should have exactly one reason to change; if describing it requires the word \"and\", it should be split\n- **DRY at the class and component level** – logic shared between two or more classes or components belongs in a shared utility, hook, or service; duplication at this level compounds and becomes the hardest kind to fix later\n- **Use dependency injection** – for testability\n\n## Don't\n\n- **Don't create new patterns** – without justification or discussion\n- **Don't tightly couple modules** – avoid circular dependencies\n- **Don't bypass abstractions** – use the data layer, don't query directly from controllers\n";

const performance_md = "# Performance\n\n## Purpose\n\nDefine performance expectations and optimization guidelines for AI-generated code.\n\n## Do\n\n- **Measure before optimizing** – use profilers and benchmarks; don't guess\n- **Cache expensive operations** – memoize, cache API calls, precompute when possible\n- **Lazy load when possible** – code splitting, dynamic imports, deferred execution\n- **Debounce/throttle** – for frequent events (scroll, resize, input)\n- **Clean up after yourself** – remove event listeners, timers, and subscriptions when done\n\n## Don't\n\n- **Don't fetch in loops** – batch API calls, use Promise.all\n- **Don't block the main thread** – use background workers for heavy computation\n- **Don't load everything upfront** – paginate or virtualize large datasets\n";

const code_review_md = "# Code Review\n\n## Purpose\n\nDefine standards for code reviews and what to look for when reviewing AI-generated code.\n\n## Do\n\n- **Check for security issues** – SQL injection, XSS, hardcoded secrets\n- **Verify error handling** – proper try/catch, error messages, fallbacks\n- **Review test coverage** – edge cases covered, meaningful assertions\n- **Check naming consistency** – follows repo conventions\n- **Look for duplication** – reusable code extracted to functions/modules\n- **Check dependencies** – necessary, up-to-date, no suspicious packages\n\n## Don't\n\n- **Don't nitpick style** – let linters/formatters handle it\n- **Don't block on preferences** – focus on correctness and maintainability\n- **Don't merge with unresolved comments** – address or explicitly defer\n- **Don't assume AI is always right** – LLMs make mistakes\n\n## Review Comment Format\n\nName the issue, explain the risk, suggest the fix:\n\n```\nThis can throw if userId is undefined.\nFix: if (!userId) throw new Error('userId required');\n\n⚠️ SQL injection risk — use parameterized queries:\n  db.query('SELECT * FROM users WHERE id = ?', [userId])\n```\n";

const error_handling_md = "# Error Handling\n\n## Purpose\n\nDefine how errors should be handled and reported in AI-generated code.\n\n## Do\n\n- **Throw meaningful errors** – include context: what failed and why\n- **Use custom error classes** – for domain-specific errors that callers need to distinguish\n- **Handle errors at the right level** – catch where you can meaningfully recover, not earlier\n- **Fail fast** – validate inputs at the entry point, throw immediately\n\n## Don't\n\n- **Don't swallow errors** – empty catch blocks hide bugs\n- **Don't use errors for control flow** – errors are for exceptional cases\n- **Don't use generic messages** – \"Something went wrong\" gives no actionable information\n";

